// 架空の事業者「みやこ交通（東京23区・横浜営業区域）」AVM 連動配車センター
//
// SSR / RSC 安全: このファイルは純データ（関数 prop なし）。固定スナップショット
// （09:42 時点）として扱い、相対時刻はクライアントで計算しない（hydration ずれ回避）。

export const CENTER = {
  company: "みやこ交通株式会社",
  center: "城南配車センター（無線 / アプリ配車）",
