  dateLabel: "2026/06/28（日）",
  weather: "曇のち雨（13:00〜 降雨予報・需要増見込み）",
} as const

/** 車両の稼働状態。色だけに依存させない（必ずラベル/アイコンを併記）。 */
export type VehicleStatus =
  | "空車" // available — 流し待機 / 付け待ち
  | "迎車" // en route to pickup
  | "実車" // occupied (賃走)
  | "支払対応" // settling fare
  | "休憩" // on break
  | "回送" // out of service / repositioning
  | "故障" // breakdown / accident

/** 状態 → Badge variant と並び順の重み（要対応ほど上位）。 */
export const STATUS_META: Record<
  VehicleStatus,
  { badge: "success" | "info" | "secondary" | "warning" | "destructive" | "outline"; rank: number; help: string }
> = {
  故障: { badge: "destructive", rank: 0, help: "車両故障 / 事故" },
  空車: { badge: "success", rank: 1, help: "配車可能" },
  迎車: { badge: "info", rank: 2, help: "迎車中" },
  実車: { badge: "secondary", rank: 3, help: "賃走中" },
  支払対応: { badge: "warning", rank: 4, help: "精算中" },
  休憩: { badge: "outline", rank: 5, help: "休憩中" },
  回送: { badge: "outline", rank: 6, help: "回送" },
}

export type DriverGrade = "優良" | "一般" | "新人"

export interface Vehicle {
  /** 号車 */
  id: string
  /** 無線番号 */
  radio: string
  driver: string
  grade: DriverGrade
  status: VehicleStatus
  /** 現在エリア（待機場所 / 走行エリア） */
  area: string
  zone: AreaZone
  /** 最終 AVM 更新からの経過（分） */
  updatedMinAgo: number
  /** 本日水揚（営収・円） */
  takings: number
  /** 本日回数（実車回数） */
  trips: number
  /** 実車率（0–1） */
  occupancyRate: number
  /** 連続乗務（時間）— 拘束時間監視用 */
  onDutyHours: number
  /** 迎車中なら到着まで（分）/ 故障なら事象 */
  note?: string
}

