  { id: "16号車", radio: "C-16", driver: "小川 健", grade: "新人", status: "休憩", area: "弁天橋 待機場", zone: "横浜・川崎", updatedMinAgo: 71, takings: 8200, trips: 3, occupancyRate: 0.22, onDutyHours: 2.0, note: "休憩 71分・無線応答なし" },
  { id: "09号車", radio: "C-09", driver: "桜井 大輔", grade: "優良", status: "回送", area: "横浜 → 品川 回送", zone: "横浜・川崎", updatedMinAgo: 2, takings: 26600, trips: 9, occupancyRate: 0.6, onDutyHours: 4.5, note: "需要薄エリアから移動中" },
  { id: "38号車", radio: "C-38", driver: "林 美咲", grade: "一般", status: "故障", area: "第一京浜（青物横丁付近）", zone: "品川・大井", updatedMinAgo: 0, takings: 14200, trips: 5, occupancyRate: 0.4, onDutyHours: 3.5, note: "エンジン警告灯・路肩停車・代車手配中" },
