export type RequestSource = "アプリ" | "電話" | "無線（流し）"

export interface RideRequest {
  id: string
  /** 受付時刻 */
  receivedAt: string
  source: RequestSource
  /** 乗車地 */
  pickup: string
  pickupZone: AreaZone
  /** 行き先 */
  dropoff: string
  /** 希望時刻（"すぐ" or "HH:MM"） */
  wantBy: string
  /** 受付からの待ち時間（分）— スナップショット固定 */
  waitMin: number
  /** 優先対応（障害者・定期・要介護 等） */
  priority?: string
  /** 想定運賃（円・概算） */
  estFare: number
  customer: string
}

export const REQUESTS: RideRequest[] = [
  { id: "R-1042", receivedAt: "09:31", source: "電話", pickup: "品川プリンスホテル 正面", pickupZone: "品川・大井", dropoff: "東京駅 八重洲口", wantBy: "すぐ", waitMin: 11, priority: "車いす利用", estFare: 2600, customer: "団体（介助1名同乗）" },
