  { id: "R-1046", receivedAt: "09:40", source: "アプリ", pickup: "横浜駅 きた西口", pickupZone: "横浜・川崎", dropoff: "みなとみらい クイーンズスクエア", wantBy: "すぐ", waitMin: 2, estFare: 1500, customer: "鈴木 様" },
  { id: "R-1047", receivedAt: "09:41", source: "無線（流し）", pickup: "羽田空港第3 到着ロビー", pickupZone: "蒲田・羽田", dropoff: "横浜 関内", wantBy: "すぐ", waitMin: 1, estFare: 6800, customer: "現地手配（係員経由）" },
