/** マッチング候補（選択中の依頼に対する近傍の空車）。
 *  距離・到着分は AVM 試算値。ETA 昇順で並ぶ前提。 */
export interface MatchCandidate {
  vehicleId: string
  /** 直線距離（km・概算） */
  distanceKm: number
  /** 到着まで（分・概算） */
  etaMin: number
}

/** requestId → 候補（近い空車のみ）。 */
