"use client"

import * as React from "react"
import {
  IconAlertTriangle,
  IconCar,
  IconClock,
  IconMapPin,
  IconPhone,
  IconDeviceMobile,
  IconRadio,
  IconUserCheck,
  IconRefresh,
} from "@tabler/icons-react"

import {
  ActionQueue,
  Badge,
  Button,
  Card,
  EmptyState,
  ListCard,
  MetadataList,
  Meter,
  Separator,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Tooltip,
  TooltipContent,
  TooltipTrigger,
  type ActionItem,
} from "@gunjo/ui"

import {
  ACTIONS,
  MATCH_CANDIDATES,
  REQUESTS,
  STATUS_META,
  VEHICLES,
  ZONES,
  pct,
  yen,
  type AreaZone,
  type RideRequest,
  type Vehicle,
  type VehicleStatus,
} from "./data"

const SOURCE_ICON: Record<RideRequest["source"], React.ReactNode> = {
  アプリ: <IconDeviceMobile className="size-3.5" aria-hidden="true" />,
  電話: <IconPhone className="size-3.5" aria-hidden="true" />,
  "無線（流し）": <IconRadio className="size-3.5" aria-hidden="true" />,
}

const GRADE_BADGE: Record<Vehicle["grade"], "success" | "secondary" | "info"> = {
  優良: "success",
  一般: "secondary",
  新人: "info",
}

function StatusBadge({ status }: { status: VehicleStatus }) {
  const meta = STATUS_META[status]
  return (
    <Badge variant={meta.badge} aria-label={`状態: ${status}（${meta.help}）`}>
      {status}
    </Badge>
  )
}

/** 状態が要対応かどうか（盤面で目立たせる対象）。 */
function isAttention(v: Vehicle): boolean {
  return v.status === "故障" || (v.status === "休憩" && v.updatedMinAgo > 30)
}

export function TaxiDispatchConsole() {
  const [zone, setZone] = React.useState<AreaZone | "all">("all")
  const [selectedVehicleId, setSelectedVehicleId] = React.useState<string | null>(null)
  const [selectedRequestId, setSelectedRequestId] = React.useState<string | null>("R-1042")
  // 既に配車確定した依頼（号車）。デモ用のローカル状態。
  const [assigned, setAssigned] = React.useState<Record<string, string>>({})

  const vehiclesInZone = React.useMemo(
    () => (zone === "all" ? VEHICLES : VEHICLES.filter((v) => v.zone === zone)),
    [zone]
  )

  // 状態順 → 要対応が上、空車が次、最終更新が古いほど上（同状態内）。
  const sortedVehicles = React.useMemo(
    () =>
      [...vehiclesInZone].sort((a, b) => {
        const r = STATUS_META[a.status].rank - STATUS_META[b.status].rank
        if (r !== 0) return r
        return b.updatedMinAgo - a.updatedMinAgo
      }),
    [vehiclesInZone]
  )

  const selectedVehicle = VEHICLES.find((v) => v.id === selectedVehicleId) ?? null
  const selectedRequest = REQUESTS.find((r) => r.id === selectedRequestId) ?? null

  const availableCount = VEHICLES.filter((v) => v.status === "空車").length
  const pendingRequests = REQUESTS.filter((r) => !assigned[r.id])

  // ── 要対応キュー（ActionQueue 用に整形） ───────────────────────────────
  const actionItems: ActionItem[] = ACTIONS.map((a) => ({
    id: a.id,
    severity: a.severity,
    kind: a.kind,
    title: a.title,
    detail: a.detail,
    meta: a.meta,
    actions:
      a.id === "A3" ? (
        <Button
          size="sm"
          variant="outline"
          onClick={() => {
            setSelectedRequestId("R-1042")
            document.getElementById("matching-panel")?.scrollIntoView({ behavior: "smooth", block: "center" })
          }}
        >
          配車画面へ
        </Button>
      ) : a.id === "A1" || a.id === "A2" ? (
        <Button
          size="sm"
          variant="outline"
          onClick={() => setSelectedVehicleId(a.id === "A1" ? "38号車" : "16号車")}
        >
          車両を表示
        </Button>
      ) : undefined,
  }))

  // ── マッチング候補 ─────────────────────────────────────────────────────
  const candidates = selectedRequest ? MATCH_CANDIDATES[selectedRequest.id] ?? [] : []

  function handleAssign(requestId: string, vehicleId: string) {
    setAssigned((prev) => ({ ...prev, [requestId]: vehicleId }))
    // 確定後、次の未配車依頼へ自動で送る
    const next = REQUESTS.find((r) => !assigned[r.id] && r.id !== requestId)
    setSelectedRequestId(next ? next.id : null)
  }

  return (
    <div className="grid grid-cols-1 gap-5 xl:grid-cols-[minmax(0,1fr)_360px]">
      {/* ════════ 左カラム: 盤面 + 依頼/マッチング ════════ */}
      <div className="flex min-w-0 flex-col gap-5">
        {/* ── 車両の状態盤 ─────────────────────────────────────────────── */}
        <section aria-labelledby="board-h">
          <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
            <div className="flex items-center gap-2">
              <h2 id="board-h" className="text-base font-bold tracking-tight">
                車両状態盤
              </h2>
              <Badge variant="outline" aria-label={`全${VEHICLES.length}台`}>
                全{VEHICLES.length}台
              </Badge>
              <Badge variant="success" aria-label={`空車${availableCount}台`}>
                空車 {availableCount}
              </Badge>
            </div>
            {/* エリア絞り込み — ToggleGroup ではなくセグメント風ボタン（多言語ラベル都合） */}
            <div className="flex flex-wrap items-center gap-1" role="group" aria-label="エリアで絞り込み">
              <Button
                size="sm"
                variant={zone === "all" ? "default" : "ghost"}
                onClick={() => setZone("all")}
                aria-pressed={zone === "all"}
              >
                全エリア
              </Button>
              {ZONES.map((z) => (
                <Button
                  key={z}
                  size="sm"
                  variant={zone === z ? "default" : "ghost"}
                  onClick={() => setZone(z)}
                  aria-pressed={zone === z}
                >
                  {z}
                </Button>
              ))}
            </div>
          </div>

          {/* 盤面本体 — @gunjo/ui に「状態盤」プリミティブが無いため手組み。
              ListCard を 1 マスとしてタイル化（号車・状態・乗務員・エリア）。 */}
          <ul
            className="grid grid-cols-1 gap-2 sm:grid-cols-2 2xl:grid-cols-3"
            aria-label={`車両状態盤（${zone === "all" ? "全エリア" : zone}）`}
          >
            {sortedVehicles.map((v) => {
              const attention = isAttention(v)
              const severity =
                v.status === "故障"
                  ? "critical"
                  : attention
                    ? "warning"
                    : v.status === "空車"
                      ? "success"
                      : undefined
              return (
                <li key={v.id}>
                  <ListCard
                    onSelect={() => setSelectedVehicleId(v.id)}
                    selected={selectedVehicleId === v.id}
                    severity={severity}
                    leading={
                      <div className="flex size-9 items-center justify-center rounded-md bg-muted text-muted-foreground">
                        <IconCar className="size-5" aria-hidden="true" />
                      </div>
                    }
                    title={
                      <span className="flex items-center gap-2">
                        {v.id}
                        <span className="text-xs font-normal text-muted-foreground">{v.radio}</span>
                        {attention && (
                          <IconAlertTriangle
                            className="size-4 text-warning"
                            aria-label="要確認"
                          />
                        )}
                      </span>
                    }
                    description={
                      <span className="flex items-center gap-1 truncate">
                        <IconMapPin className="size-3.5 shrink-0" aria-hidden="true" />
                        {v.area}
                      </span>
                    }
                    tags={
                      <>
                        <span className="text-xs text-muted-foreground">{v.driver}</span>
                        <Badge variant={GRADE_BADGE[v.grade]}>{v.grade}</Badge>
                      </>
                    }
                    status={<StatusBadge status={v.status} />}
                    meta={
                      v.note
                        ? v.note
                        : v.updatedMinAgo === 0
                          ? "更新 たった今"
                          : `更新 ${v.updatedMinAgo}分前`
                    }
                  />
                </li>
              )
            })}
          </ul>
          {sortedVehicles.length === 0 && (
            <EmptyState
              icon={<IconCar className="size-6" aria-hidden="true" />}
              title="該当する車両はありません"
              description="エリアの絞り込みを変更してください。"
            />
          )}
        </section>

        {/* ── 配車依頼キュー + マッチング ─────────────────────────────── */}
        <section id="matching-panel" aria-labelledby="req-h" className="scroll-mt-4">
          <div className="mb-3 flex items-center gap-2">
            <h2 id="req-h" className="text-base font-bold tracking-tight">
              配車依頼
            </h2>
            <Badge variant={pendingRequests.length > 0 ? "warning" : "success"}>
              待ち {pendingRequests.length}件
            </Badge>
          </div>

          <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
            {/* 左: 依頼リスト */}
            <Card className="p-3">
              <h3 className="mb-2 px-1 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                受付キュー（待ち時間順）
              </h3>
              <ul className="flex flex-col gap-2" aria-label="配車依頼キュー">
                {[...REQUESTS]
                  .sort((a, b) => b.waitMin - a.waitMin)
                  .map((r) => {
                    const done = assigned[r.id]
                    return (
                      <li key={r.id}>
                        <ListCard
                          onSelect={() => setSelectedRequestId(r.id)}
                          selected={selectedRequestId === r.id}
                          severity={done ? "success" : r.waitMin >= 10 ? "warning" : undefined}
                          title={
                            <span className="flex items-center gap-2">
                              <span className="flex items-center gap-1 text-xs font-medium text-muted-foreground">
                                {SOURCE_ICON[r.source]}
                                {r.source}
                              </span>
                              {r.pickup}
                            </span>
                          }
                          description={`→ ${r.dropoff}　/　${r.customer}`}
                          tags={
                            <>
                              {r.priority && <Badge variant="info">{r.priority}</Badge>}
                              <Badge variant="outline">希望 {r.wantBy}</Badge>
                              <span className="text-xs text-muted-foreground">{yen(r.estFare)} 概算</span>
                            </>
                          }
                          status={
                            done ? (
                              <Badge variant="success">{done} 確定</Badge>
                            ) : (
                              <Badge variant={r.waitMin >= 10 ? "warning" : "secondary"}>
                                待ち {r.waitMin}分
                              </Badge>
                            )
                          }
                          meta={`受付 ${r.receivedAt}`}
                        />
                      </li>
                    )
                  })}
              </ul>
            </Card>

            {/* 右: マッチング（選択依頼 + 近傍の空車候補 + 配車アクション） */}
            <Card className="flex flex-col p-3">
              <h3 className="mb-2 px-1 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                マッチング（近傍の空車）
              </h3>
              {!selectedRequest ? (
                <EmptyState
                  className="my-auto"
                  icon={<IconUserCheck className="size-6" aria-hidden="true" />}
                  title="依頼を選択してください"
                  description="左の受付キューから 1 件選ぶと、近くの空車候補が表示されます。"
                />
              ) : (
                <div className="flex min-w-0 flex-col gap-3">
                  {/* 選択中の依頼サマリ */}
                  <div className="rounded-md border border-border bg-muted/40 p-3">
                    <div className="mb-1 flex items-center justify-between gap-2">
                      <span className="font-semibold">{selectedRequest.id}</span>
                      <span className="flex items-center gap-1 text-xs text-muted-foreground">
                        {SOURCE_ICON[selectedRequest.source]}
                        {selectedRequest.source}　受付 {selectedRequest.receivedAt}
                      </span>
                    </div>
                    <MetadataList
                      variant="compact"
                      items={[
                        { label: "乗車地", value: selectedRequest.pickup },
                        { label: "行き先", value: selectedRequest.dropoff },
                        {
                          label: "優先 / 希望",
                          value: `${selectedRequest.priority ?? "—"}　/　${selectedRequest.wantBy}`,
                        },
                        { label: "概算運賃", value: yen(selectedRequest.estFare) },
                      ]}
                    />
                  </div>

                  {assigned[selectedRequest.id] ? (
                    <div
                      className="rounded-md border border-success-border bg-success-subtle px-3 py-2 text-sm text-success-subtle-foreground"
                      role="status"
                    >
                      {assigned[selectedRequest.id]} に配車を確定しました。
                    </div>
                  ) : candidates.length === 0 ? (
                    <EmptyState
                      icon={<IconAlertTriangle className="size-6" aria-hidden="true" />}
                      title="近傍に空車がありません"
                      description="このエリアは空車が枯渇しています。回送車の再指示、または近隣エリアからの応援を検討してください。"
                    />
                  ) : (
                    <ul className="flex flex-col gap-2" aria-label={`${selectedRequest.id} の配車候補`}>
                      {candidates.map((c, i) => {
                        const v = VEHICLES.find((x) => x.id === c.vehicleId)
                        if (!v) return null
                        return (
                          <li key={c.vehicleId}>
                            <ListCard
                              severity={i === 0 ? "success" : undefined}
                              leading={
                                <div className="flex size-9 shrink-0 flex-col items-center justify-center rounded-md bg-primary/10 text-xs font-bold text-primary">
                                  {c.etaMin}
                                  <span className="text-[9px] font-normal">分</span>
                                </div>
                              }
                              title={
                                <span className="flex items-center gap-2">
                                  {v.id}
                                  {i === 0 && <Badge variant="success">最寄り</Badge>}
                                </span>
                              }
                              description={`${v.driver}・${v.area}`}
                              tags={
                                <>
                                  <Badge variant={GRADE_BADGE[v.grade]}>{v.grade}</Badge>
                                  <span className="text-xs text-muted-foreground">約 {c.distanceKm}km</span>
                                </>
                              }
                              status={
                                <Button size="sm" onClick={() => handleAssign(selectedRequest.id, v.id)}>
                                  配車
                                </Button>
                              }
                            />
                          </li>
                        )
                      })}
                    </ul>
                  )}
                </div>
              )}
            </Card>
          </div>
        </section>
      </div>

      {/* ════════ 右カラム: 要対応 + 車両詳細インスペクタ ════════ */}
      <aside className="flex min-w-0 flex-col gap-5" aria-label="要対応と詳細">
        <section aria-labelledby="action-h">
          <div className="mb-3 flex items-center gap-2">
            <h2 id="action-h" className="text-base font-bold tracking-tight">
              要対応
            </h2>
            <Badge variant="destructive">{ACTIONS.filter((a) => a.severity === "critical").length} 重大</Badge>
          </div>
          <ActionQueue items={actionItems} />
        </section>

        <Separator />

        {/* 詳細インスペクタ — 選択中の車両 */}
        <section aria-labelledby="detail-h">
          <div className="mb-3 flex items-center justify-between gap-2">
            <h2 id="detail-h" className="text-base font-bold tracking-tight">
              車両詳細
            </h2>
            {selectedVehicle && (
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon"
                    variant="ghost"
                    aria-label="AVM を再取得"
                    onClick={() => undefined}
                  >
                    <IconRefresh className="size-4" aria-hidden="true" />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>AVM を再取得</TooltipContent>
              </Tooltip>
            )}
          </div>
          {!selectedVehicle ? (
            <EmptyState
              icon={<IconCar className="size-6" aria-hidden="true" />}
              title="車両を選択してください"
              description="盤面の号車をクリックすると、乗務員・本日営収・状態がここに表示されます。"
            />
          ) : (
            <Card className="flex flex-col gap-4 p-4">
              <div className="flex items-start justify-between gap-2">
                <div>
                  <div className="flex items-center gap-2">
                    <span className="text-lg font-bold">{selectedVehicle.id}</span>
                    <StatusBadge status={selectedVehicle.status} />
                  </div>
                  <p className="mt-0.5 text-sm text-muted-foreground">
                    {selectedVehicle.driver}・{selectedVehicle.radio}
                  </p>
                </div>
                <Badge variant={GRADE_BADGE[selectedVehicle.grade]}>{selectedVehicle.grade}乗務員</Badge>
              </div>

              {selectedVehicle.note && (
                <div className="flex items-start gap-2 rounded-md border border-warning-border bg-warning-subtle px-3 py-2 text-xs text-warning-subtle-foreground">
                  <IconAlertTriangle className="mt-0.5 size-4 shrink-0" aria-hidden="true" />
                  <span>{selectedVehicle.note}</span>
                </div>
              )}

              <Tabs defaultValue="status">
                <TabsList className="w-full">
                  <TabsTrigger value="status" className="flex-1">
                    稼働
                  </TabsTrigger>
                  <TabsTrigger value="takings" className="flex-1">
                    営収
                  </TabsTrigger>
                </TabsList>
                <TabsContent value="status" className="!mt-3 !p-0">
                  <MetadataList
                    items={[
                      {
                        label: "現在エリア",
                        value: (
                          <span className="flex items-center gap-1">
                            <IconMapPin className="size-3.5" aria-hidden="true" />
                            {selectedVehicle.area}
                          </span>
                        ),
                      },
                      {
                        label: "最終更新",
                        value:
                          selectedVehicle.updatedMinAgo === 0
                            ? "たった今"
                            : `${selectedVehicle.updatedMinAgo}分前`,
                      },
                      { label: "連続乗務", value: `${selectedVehicle.onDutyHours} 時間` },
                    ]}
                  />
                  <div className="mt-3">
                    <div className="mb-1 flex items-center justify-between text-xs">
                      <span className="font-medium text-muted-foreground">拘束時間（上限13時間）</span>
                      <span className="tabular-nums">{selectedVehicle.onDutyHours} / 13h</span>
                    </div>
                    <Meter
                      value={selectedVehicle.onDutyHours}
                      max={13}
                      thresholds={{ warning: 0.77, over: 1 }}
                      label={`${selectedVehicle.id} の連続乗務時間`}
                      unit="h"
                    />
                  </div>
                </TabsContent>
                <TabsContent value="takings" className="!mt-3 !p-0">
                  <MetadataList
                    items={[
                      { label: "本日水揚（営収）", value: yen(selectedVehicle.takings) },
                      { label: "実車回数", value: `${selectedVehicle.trips} 回` },
                      { label: "実車率", value: pct(selectedVehicle.occupancyRate) },
                    ]}
                  />
                  <div className="mt-3">
                    <div className="mb-1 flex items-center justify-between text-xs">
                      <span className="font-medium text-muted-foreground">実車率（目標 60%）</span>
                      <span className="tabular-nums">{pct(selectedVehicle.occupancyRate)}</span>
                    </div>
                    <Meter
                      value={selectedVehicle.occupancyRate * 100}
                      max={100}
                      target={60}
                      direction="higher-is-better"
                      label={`${selectedVehicle.id} の実車率`}
                      unit="%"
                    />
                  </div>
                </TabsContent>
              </Tabs>

              <div className="flex gap-2">
                <Button size="sm" variant="outline" className="flex-1">
                  <IconRadio className="size-4" aria-hidden="true" />
                  無線呼出
                </Button>
                <Button size="sm" variant="outline" className="flex-1">
                  <IconClock className="size-4" aria-hidden="true" />
                  休憩指示
                </Button>
              </div>
            </Card>
          )}
        </section>
      </aside>
    </div>
  )
}
